class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: GetEnvironmentVariable now returns null for
        // empty values on Unix. Use !Environment.HasEnvironmentVariable to
        // detect "not set" vs "explicitly empty".
        if (!Environment.HasEnvironmentVariable("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

